import { NextRequest, NextResponse } from 'next/server';
import OpenAI from 'openai';
import { createClient } from '@supabase/supabase-js';
import sharp from 'sharp';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

const FONT_R = "";
const FONT_B = "";

function ff() {
  return `@font-face{font-family:"KF";font-weight:normal;src:url("data:font/truetype;base64,${FONT_R}");}` +
         `@font-face{font-family:"KF";font-weight:bold;src:url("data:font/truetype;base64,${FONT_B}");}`;
}

function esc(s: string) {
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

function wrapText(text: string, maxChars: number): string[] {
  const words = text.split(' ');
  const lines: string[] = [];
  let cur = '';
  for (const w of words) {
    if ((cur + ' ' + w).trim().length > maxChars && cur) {
      lines.push(cur.trim()); cur = w;
    } else cur = (cur + ' ' + w).trim();
  }
  if (cur) lines.push(cur);
  return lines;
}

async function uploadToStorage(
  supabase: ReturnType<typeof createClient>,
  buffer: Buffer, userId: string,
): Promise<string | null> {
  try {
    const fileName = `banners/${userId}/${Date.now()}-ai.jpg`;
    const { error } = await supabase.storage
      .from('card-images')
      .upload(fileName, buffer, { contentType: 'image/jpeg' });
    if (error) return null;
    const { data } = supabase.storage.from('card-images').getPublicUrl(fileName);
    return data.publicUrl;
  } catch { return null; }
}

// ── Step 1: GPT-4o аналізує товар → промпт для DALL-E 3 (тільки фон/дизайн) ─
async function buildBackgroundPrompt(
  imageBase64: string,
  productName: string,
  category: string,
  platform: string,
): Promise<string> {

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [{
      role: 'user',
      content: [
        {
          type: 'image_url',
          image_url: {
            url: imageBase64.startsWith('data:') ? imageBase64 : `data:image/jpeg;base64,${imageBase64}`,
            detail: 'low',
          },
        },
        {
          type: 'text',
          text: `You are a professional marketing designer for Ukrainian marketplaces.

Analyze this product photo and create a DALL-E 3 prompt for a BACKGROUND ONLY.

Product: "${productName}"
Category: "${category || 'general'}"
Platform: "${platform}"

CRITICAL RULES:
- The background must have NO text, NO words, NO letters whatsoever
- The background must have NO product in it — just environment/atmosphere
- Leave clear empty space on the LEFT side (60% of image) where the product photo will be placed
- Right side (40%) should have subtle design elements, patterns, or texture
- Style should match the product: tactical/military = dark olive/khaki tones, tech = dark blue, beauty = soft gradients, etc
- Extract the dominant color palette from the product photo
- Make it look like a premium Ukrainian marketplace banner background

Write ONLY the image generation prompt in English. Be specific about colors, textures, lighting, mood. 
Start with: "Abstract marketing banner background for"`,
        },
      ],
    }],
    max_tokens: 400,
    temperature: 0.8,
  });

  return response.choices[0]?.message?.content ?? 
    'Abstract dark marketing banner background with subtle geometric patterns, premium quality, no text, no products, gradient from dark olive to black';
}

// ── Step 2: Зібрати фінальний банер через sharp ──────────────────────────────
async function composeBanner(
  bgBuffer: Buffer,
  photoBuf: Buffer,
  productName: string,
  bullets: string[],
  price: string,
  accentColor: string,
): Promise<Buffer> {
  const W = 1024, H = 1024;

  // Resize bg to 1024x1024
  const bg = await sharp(bgBuffer).resize(W, H).jpeg({ quality: 95 }).toBuffer();

  const composites: sharp.OverlayOptions[] = [];

  // ── Product photo — left side ──
  const photoSize = 580;
  const photoResized = await sharp(photoBuf)
    .resize(photoSize, photoSize, { fit: 'contain', background: { r: 0, g: 0, b: 0, alpha: 0 } })
    .png()
    .toBuffer();
  composites.push({ input: photoResized, left: 20, top: Math.round((H - photoSize) / 2) });

  // ── Right panel — semi-transparent overlay ──
  const panelX = 580, panelW = 420, panelH = H;
  const panelSvg = Buffer.from(
    `<svg width="${panelW}" height="${panelH}" xmlns="http://www.w3.org/2000/svg">
      <rect width="${panelW}" height="${panelH}" fill="rgba(0,0,0,0.72)"/>
    </svg>`
  );
  const panelBuf = await sharp(panelSvg).png().toBuffer();
  composites.push({ input: panelBuf, left: panelX, top: 0 });

  // ── Accent line ──
  const accentLineSvg = Buffer.from(
    `<svg width="4" height="${panelH}" xmlns="http://www.w3.org/2000/svg">
      <rect width="4" height="${panelH}" fill="${accentColor}"/>
    </svg>`
  );
  const accentLineBuf = await sharp(accentLineSvg).png().toBuffer();
  composites.push({ input: accentLineBuf, left: panelX, top: 0 });

  // ── Text SVG — all at once ──
  const tx = panelX + 28;
  const pw = panelW - 56;
  const nameLines = wrapText(productName, Math.floor(pw / (22 * 0.58)));

  let inner = '';

  // Badge
  inner += `<rect x="0" y="40" width="100" height="26" rx="13" fill="${accentColor}" opacity="0.25"/>`;
  inner += `<rect x="0" y="40" width="100" height="26" rx="13" fill="none" stroke="${accentColor}" stroke-width="1" opacity="0.6"/>`;
  inner += `<text x="50" y="58" text-anchor="middle" font-family="KF,sans-serif" font-size="11" font-weight="bold" fill="${accentColor}" letter-spacing="2">ПРЕМІУМ</text>`;

  // Product name
  let ny = 94;
  nameLines.forEach((line, i) => {
    inner += `<text x="0" y="${ny}" font-family="KF,sans-serif" font-size="22" font-weight="bold" fill="${i === 0 ? '#ffffff' : accentColor}">${esc(line)}</text>`;
    ny += 30;
  });

  // Divider
  inner += `<line x1="0" y1="${ny + 8}" x2="${pw}" y2="${ny + 8}" stroke="${accentColor}" stroke-width="1" opacity="0.35"/>`;
  ny += 28;

  // Bullets
  const activeBullets = bullets.filter(b => b.trim()).slice(0, 4);
  if (activeBullets.length === 0) {
    // No bullets — just accent decoration
    inner += `<text x="0" y="${ny + 20}" font-family="KF,sans-serif" font-size="14" fill="rgba(255,255,255,0.5)">Якісний товар</text>`;
    ny += 50;
  } else {
    for (let i = 0; i < activeBullets.length; i++) {
      // Circle
      inner += `<circle cx="10" cy="${ny + 8}" r="9" fill="${accentColor}" opacity="0.2"/>`;
      inner += `<circle cx="10" cy="${ny + 8}" r="9" fill="none" stroke="${accentColor}" stroke-width="1" opacity="0.5"/>`;
      inner += `<text x="10" y="${ny + 13}" text-anchor="middle" font-family="KF,sans-serif" font-size="10" font-weight="bold" fill="${accentColor}">✓</text>`;
      // Text
      const bl = wrapText(activeBullets[i], Math.floor((pw - 30) / (14 * 0.58)));
      bl.forEach((l, bi) => {
        inner += `<text x="28" y="${ny + 14 + bi * 18}" font-family="KF,sans-serif" font-size="14" fill="#ffffff">${esc(l)}</text>`;
      });
      ny += Math.max(bl.length * 18 + 4, 26) + 16;
      if (i < activeBullets.length - 1) {
        inner += `<line x1="0" y1="${ny}" x2="${pw}" y2="${ny}" stroke="rgba(255,255,255,0.08)" stroke-width="1"/>`;
        ny += 14;
      }
    }
  }

  // Price
  if (price.trim()) {
    const priceY = Math.min(ny + 40, 880);
    inner += `<rect x="0" y="${priceY}" width="${pw}" height="56" rx="12" fill="${accentColor}" opacity="0.15"/>`;
    inner += `<text x="${pw/2}" y="${priceY + 36}" text-anchor="middle" font-family="KF,sans-serif" font-size="34" font-weight="bold" fill="${accentColor}">${esc(price)} ₴</text>`;
  }

  // CTA bottom
  inner += `<rect x="0" y="${panelH - 56}" width="${pw}" height="44" rx="10" fill="${accentColor}"/>`;
  inner += `<text x="${pw/2}" y="${panelH - 26}" text-anchor="middle" font-family="KF,sans-serif" font-size="15" font-weight="bold" fill="#000000">ЗАМОВИТИ ЗАРАЗ</text>`;

  const textSvg = `<?xml version="1.0" encoding="UTF-8"?>
<svg width="${pw}" height="${panelH}" xmlns="http://www.w3.org/2000/svg">
  <style>${ff()}</style>
  ${inner}
</svg>`;

  const textBuf = await sharp(Buffer.from(textSvg, 'utf-8')).png().toBuffer();
  composites.push({ input: textBuf, left: tx, top: 0 });

  // Compose everything onto background
  return sharp(bg)
    .composite(composites)
    .jpeg({ quality: 93 })
    .toBuffer();
}

// ── Main handler ──────────────────────────────────────────────────────────────
export async function POST(req: NextRequest) {
  try {
    const authHeader = req.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    if (!token) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const supabase = createClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      { global: { headers: { Authorization: `Bearer ${token}` } } },
    );
    const { data: { user } } = await supabase.auth.getUser(token);
    if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const {
      productB64,
      productName = '',
      bullets = [],
      price = '',
      platform = 'general',
      category = '',
    } = await req.json();

    if (!productB64) return NextResponse.json({ error: 'Потрібне фото товару' }, { status: 400 });
    if (!productName.trim()) return NextResponse.json({ error: 'Потрібна назва товару' }, { status: 400 });

    const b = (bullets as string[]).filter((x: string) => x.trim()).slice(0, 4)
      .map((x: string) => x.replace(/^[✓•]\s*/, '').trim());

    // ── Step 1: GPT-4o → background prompt ──────────────────────────────────
    const bgPrompt = await buildBackgroundPrompt(productB64, productName, category, platform);

    // ── Step 2: DALL-E 3 → background image ─────────────────────────────────
    const dalleRes = await openai.images.generate({
      model: 'dall-e-3',
      prompt: bgPrompt + ' NO TEXT. NO WORDS. NO LETTERS. Background only.',
      size: '1024x1024',
      quality: 'hd',
      style: 'vivid',
      n: 1,
      response_format: 'b64_json',
    });

    const bgB64 = dalleRes.data[0]?.b64_json;
    if (!bgB64) throw new Error('DALL-E 3 не повернув зображення');
    const bgBuffer = Buffer.from(bgB64, 'base64');

    // ── Step 3: Decode product photo ────────────────────────────────────────
    const photoData = productB64.replace(/^data:image\/\w+;base64,/, '');
    const photoBuf = Buffer.from(photoData, 'base64');

    // ── Step 4: Detect accent color from product photo ───────────────────────
    // Use a category-based accent as fallback
    const categoryAccents: Record<string, string> = {
      'Одяг та взуття':       '#c8a84b',
      'Тактичне спорядження': '#7aaa5a',
      'Електроніка':          '#4a9eff',
      'Спорт та хобі':        '#ff6b35',
      'Краса та здоров\'я':  '#e87aa0',
      'Авто та мото':         '#e0a020',
      'Іграшки':              '#8855ee',
      'Дім та сад':           '#6ab04c',
    };
    const accent = categoryAccents[category] ?? '#c8a84b';

    // ── Step 5: Compose final banner ─────────────────────────────────────────
    const finalBuffer = await composeBanner(bgBuffer, photoBuf, productName, b, price, accent);

    // ── Step 6: Upload ────────────────────────────────────────────────────────
    const permanent = await uploadToStorage(supabase, finalBuffer, user.id);
    const b64Out = finalBuffer.toString('base64');

    return NextResponse.json({
      imageUrl: permanent ?? `data:image/jpeg;base64,${b64Out}`,
      imageB64: `data:image/jpeg;base64,${b64Out}`,
    });

  } catch (err: unknown) {
    console.error('Generate banner error:', err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : 'Помилка генерації' },
      { status: 500 },
    );
  }
}
